public int minAppendKSum(int[] nums, int k) {
    int max_elem = Arrays.stream(nums).max().getAsInt();
    int sum = 0;
    for (int i = max_elem + 1; i <= max_elem + k; i++) {
        sum += i;
    }
    return sum;
}
```

